package be.schaubroeck.lpb.rkm.rekenmotor.rsz;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetal;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuut;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelsel;
import be.schaubroeck.lpb.tools.rsz.dmfa.CategorieKengetalStatuutPensioenstelselDmfa;
import be.schaubroeck.lpb.tools.rsz.dmfappl.CategorieKengetalStatuutPensioenstelselDmfappl;

public class CategorieKengetalStatuutPensioenstelselFactory {
    private CategorieKengetalStatuutPensioenstelselFactory() {
    }

    public static CategorieKengetalStatuutPensioenstelsel create(
            RekenTijd rekenTijd, WerkgeversCategorie categorie, DmfapplWnkengetal kengetal, DmfapplStatuutDmfappl statuutDmfappl, Pensioenstelsel pensioenstelsel) {
        CategorieKengetal categorieKengetal = CategorieKengetalFactory.getCategorieKengetal(rekenTijd, categorie, kengetal);
        CategorieKengetalStatuut categorieKengetalStatuut = CategorieKengetalStatuutFactory.getCategorieKengetalStatuut(rekenTijd, categorieKengetal, statuutDmfappl);
        return create(rekenTijd, categorieKengetalStatuut, pensioenstelsel);
    }

    public static CategorieKengetalStatuutPensioenstelsel create(
            RekenTijd rekenTijd, CategorieKengetalStatuut categorieKengetalStatuut, Pensioenstelsel pensioenstelsel) {
        if (rekenTijd.isDmfa()) {
            return new CategorieKengetalStatuutPensioenstelselDmfa(categorieKengetalStatuut, pensioenstelsel);
        } else {
            return new CategorieKengetalStatuutPensioenstelselDmfappl(categorieKengetalStatuut, pensioenstelsel);
        }
    }

    public static CategorieKengetalStatuutPensioenstelsel create(
            RkmTijdperk tijdperk, CategorieKengetalStatuut categorieKengetalStatuut, Pensioenstelsel pensioenstelsel) {
        if (tijdperk == RkmTijdperk.DMFA) {
            return new CategorieKengetalStatuutPensioenstelselDmfa(categorieKengetalStatuut, pensioenstelsel);
        } else {
            return new CategorieKengetalStatuutPensioenstelselDmfappl(categorieKengetalStatuut, pensioenstelsel);
        }
    }

}
